local TD = TD.td1madao["ydj_dst_td1madao"] local myComponent = Class(function(self, inst)     self.inst = inst     self.handler = TheInput:AddKeyHandler(function(key, down) self:player_keyHandler(key, down) end) end) function myComponent:player_keyHandler(key, down)     if self.inst then         local player = self.inst         if player ~= nil then             if key and not down then                 player:PushEvent("keyup", { inst = self.inst, player = player, key = key })             end         end     end end function myComponent:addSkill(tag, cd)     local inst = self.inst     if self.inst and TD.isStr(tag) and TD.isNative(cd) then         local inst = self.inst         TD.csv(inst, function(comp)             if not TD.isTab(comp:get("skillcast")) then                 comp:value("skillcast", {}, true, true)             end             local skillcast = comp:get("skillcast")             local info = TD.default(skillcast, tag)             if not TD.isNative(info.cd) then                 info.cd = cd             end             info.maxcd = cd         end)         TD.player(inst, function()             if not inst[string.format("%s_key_listener_%s", TD.holder(), tag)] then                 local hotkey = TD.hotkey(tag)                 self.inst:ListenForEvent("keyup", function(inst, data)                     if data.inst == self.inst and data.key == hotkey then                         self:player_cast(tag)                     end                 end)                 inst[string.format("%s_key_listener_%s", TD.holder(), tag)] = true             end         end)     end end function myComponent:player_cast(tag)     local skill_effect = TD.cse(self.inst)     if self.inst and TD.isStr(tag) and skill_effect and TD.isFn(skill_effect[tag]) then         skill_effect[tag](skill_effect)     end end function myComponent:flush()     if self.inst then         local inst = self.inst         TD.csv(inst):changeTab("skillcast", function(elem)                          TD.fori(elem, function(k, v)                 if k ~= nil and v ~= nil then                     if TD.isPos(v.maxcd) then                         v.cd = TD.minus(v.cd)                         TD.player(self.inst, function()                                                          local param = {}                             TD.exeClient(TD.holder("%s_flush_cd"), param)                         end)                     elseif v.cd > 0 then                         v.cd = 0                     end                 end             end)         end, true)     end end function myComponent:inCD(tag)     if self.inst and TD.isStr(tag) then         local inst = self.inst         if TD.csv(inst):get("skillcast")[tag].cd <= 0 then             return false         end     end     return true end function myComponent:canCast(tag)     return not self:inCD(tag) end function myComponent:froze(tag)     if self.inst and TD.isStr(tag) then         local inst = self.inst         TD.csv(inst):changeTab("skillcast", function(elem)             local info = elem[tag]             info.cd = info.maxcd         end)     end end function myComponent:registered(tag, cd)     self:addSkill(tag, cd) end return myComponent 